import numpy as np, time
import scipy.linalg as la
from scipy.linalg.lapack import dgeev

def ref(A):
 w,V=np.linalg.eig(A); idx=np.argmax(np.abs(w)); return w[idx], V[:,idx]

def sp(A):
 w,V=la.eig(A, left=False, right=True, overwrite_a=False, check_finite=False)
 idx=np.argmax(np.abs(w)); return w[idx], V[:,idx]

def sp2(A):
 w,V=la.eig(A, left=False, right=True, overwrite_a=True, check_finite=False)
 idx=np.argmax(np.abs(w)); return w[idx], V[:,idx]

def low(A):
 # dgeev returns wr, wi, vl, vr, info? check
 out=dgeev(A, compute_vl=0, compute_vr=1, overwrite_a=0)
 wr,wi,vl,vr,info=out
 # convert dominant and vector, for real LAPACK format complex pairs encoded in adjacent columns
 mags=wr*wr+wi*wi; idx=int(mags.argmax())
 lam=complex(wr[idx], wi[idx])
 if wi[idx]==0:
   v=vr[:,idx].astype(np.complex128)
 elif wi[idx]>0:
   v=vr[:,idx].astype(np.complex128)+1j*vr[:,idx+1]
 else:
   v=vr[:,idx-1].astype(np.complex128)-1j*vr[:,idx]
 return lam,v

for n in [2,3,4,5,6,8,10]:
